import { Level } from './types';

export const MONEY_TREE: Level[] = [
  { id: 15, amount: "₹7 Crore", isSafeZone: true },
  { id: 14, amount: "₹5 Crore", isSafeZone: false },
  { id: 13, amount: "₹3 Crore", isSafeZone: true },
  { id: 12, amount: "₹1 Crore", isSafeZone: false },
  { id: 11, amount: "₹50,00,000", isSafeZone: false },
  { id: 10, amount: "₹25,00,000", isSafeZone: true },
  { id: 9, amount: "₹12,50,000", isSafeZone: false },
  { id: 8, amount: "₹6,40,000", isSafeZone: false },
  { id: 7, amount: "₹3,20,000", isSafeZone: false },
  { id: 6, amount: "₹1,60,000", isSafeZone: false },
  { id: 5, amount: "₹80,000", isSafeZone: true },
  { id: 4, amount: "₹40,000", isSafeZone: false },
  { id: 3, amount: "₹20,000", isSafeZone: false },
  { id: 2, amount: "₹10,000", isSafeZone: false },
  { id: 1, amount: "₹5,000", isSafeZone: false },
].sort((a, b) => b.id - a.id);

export const getTimerForLevel = (level: number): number | null => {
  // Q1 to Q5: 45-second timer.
  if (level <= 5) return 45;
  // Q6 to Q10: 60-second timer.
  if (level <= 10) return 60;
  // Q11 to Q15: No timer (unlimited time).
  return null;
};

import { GoogleGenAI, Type } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchQuestion = async (level: number, lang: Language): Promise<Question> => {
  const difficulty = level <= 5 ? "easy" : level <= 10 ? "medium" : "extremely hard";
  const languageName = lang === Language.HINDI ? "Hindi" : "English";

  // Adding a random seed to the prompt ensures variety in generated content
  const randomFactor = Math.random().toString(36).substring(7);

  const prompt = `Generate a UNIQUE and fresh multiple-choice question for a KBC-style quiz in ${languageName}.
  Difficulty: ${difficulty} (Level ${level} of 15).
  Target Topic: Pick a random topic from History, Geography, Science, Mythology, Sports, Movies, or Global Current Affairs.
  Seed: ${randomFactor}

  Rules:
  - Do NOT repeat common or basic trivia.
  - Make it challenging and interesting.
  - Return ONLY a JSON object.
  - For higher levels, focus on obscure facts.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING },
            options: {
              type: Type.OBJECT,
              properties: {
                A: { type: Type.STRING },
                B: { type: Type.STRING },
                C: { type: Type.STRING },
                D: { type: Type.STRING }
              },
              required: ["A", "B", "C", "D"]
            },
            correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
            explanation: { type: Type.STRING }
          },
          required: ["text", "options", "correctAnswer", "explanation"]
        }
      }
    });

    const data = JSON.parse(response.text || "{}");
    return data as Question;
  } catch (error) {
    console.error("Error fetching question:", error);
    // Fallback question
    return {
      text: lang === Language.HINDI ? "किस भारतीय राज्य को 'बादलों का घर' कहा जाता है?" : "Which Indian state is known as the 'Abode of Clouds'?",
      options: {
        A: lang === Language.HINDI ? "असम" : "Assam",
        B: lang === Language.HINDI ? "मेघालय" : "Meghalaya",
        C: lang === Language.HINDI ? "सिक्किम" : "Sikkim",
        D: lang === Language.HINDI ? "अरुणाचल प्रदेश" : "Arunachal Pradesh"
      },
      correctAnswer: "B",
      explanation: "Meghalaya translates to 'Abode of Clouds' in Sanskrit."
    };
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import LanguageSelection from './components/LanguageSelection';
import Disclaimer from './components/Disclaimer';
import Sidebar from './components/Sidebar';
import QuizArea from './components/QuizArea';
import Lifelines from './components/Lifelines';
import GameOver from './components/GameOver';
import { Language, GameStatus, Question, Lifelines as LifelinesType, PollData } from './types';
import { fetchQuestion } from './services/gemini';
import { getTimerForLevel, MONEY_TREE } from './constants';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.LANGUAGE_SELECT);
  const [language, setLanguage] = useState<Language>(Language.ENGLISH);
  const [level, setLevel] = useState(1);
  const [question, setQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(false);
  const [timeLeft, setTimeLeft] = useState<number | null>(null);
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);
  const [pollData, setPollData] = useState<PollData | null>(null);
  const [isDoubleDipActive, setIsDoubleDipActive] = useState(false);
  const [lifelines, setLifelines] = useState<LifelinesType>({
    fiftyFifty: true,
    audiencePoll: true,
    doubleDip: true,
    flipQuestion: true
  });

  const timerRef = useRef<any>(null);

  const loadQuestion = async (currLevel: number, lang: Language) => {
    setLoading(true);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);

    try {
      const q = await fetchQuestion(currLevel, lang);
      const initialTime = getTimerForLevel(currLevel);

      setTimeLeft(initialTime);
      setQuestion(q);
    } catch (error) {
      console.error("Failed to load question", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (status === GameStatus.PLAYING && timeLeft !== null && timeLeft > 0 && !loading) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev === null) return null;
          if (prev <= 1) {
            clearInterval(timerRef.current);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else if (status === GameStatus.PLAYING && timeLeft === 0 && !loading) {
      handleAnswer(false, false);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status, timeLeft, loading]);

  const handleLanguageSelect = (lang: Language) => {
    setLanguage(lang);
    setStatus(GameStatus.DISCLAIMER);
  };

  const handleStartGame = () => {
    setStatus(GameStatus.PLAYING);
    loadQuestion(1, language);
  };

  const handleAnswer = (isCorrect: boolean, isFirstAttemptOfDoubleDip: boolean) => {
    if (isFirstAttemptOfDoubleDip) {
      return;
    }

    if (timerRef.current) clearInterval(timerRef.current);

    if (isCorrect) {
      setTimeout(() => {
        if (level === 15) {
          setStatus(GameStatus.WON);
        } else {
          const nextLevel = level + 1;
          setLevel(nextLevel);
          loadQuestion(nextLevel, language);
        }
      }, 2000);
    } else {
      setTimeout(() => {
        setStatus(GameStatus.LOST);
      }, 1500);
    }
  };

  const useLifeline = (type: keyof LifelinesType) => {
    if (!question || loading) return;

    setLifelines(prev => ({ ...prev, [type]: false }));

    if (type === 'fiftyFifty') {
      const incorrect = Object.keys(question.options).filter(k => k !== question.correctAnswer);
      const shuffled = incorrect.sort(() => 0.5 - Math.random());
      setHiddenOptions(shuffled.slice(0, 2));
    } else if (type === 'audiencePoll') {
      const correct = question.correctAnswer as keyof PollData;
      const data: PollData = { A: 0, B: 0, C: 0, D: 0 };

      const correctVal = Math.floor(Math.random() * 30) + 40; 
      data[correct] = correctVal;

      let remaining = 100 - correctVal;
      const keys = (['A', 'B', 'C', 'D'] as (keyof PollData)[]).filter(k => k !== correct);

      const p1 = Math.floor(Math.random() * (remaining - 5));
      data[keys[0]] = p1;
      remaining -= p1;

      const p2 = Math.floor(Math.random() * remaining);
      data[keys[1]] = p2;
      data[keys[2]] = remaining - p2;

      setPollData(data);
    } else if (type === 'doubleDip') {
      setIsDoubleDipActive(true);
    } else if (type === 'flipQuestion') {
      loadQuestion(level, language);
    }
  };

  const restartGame = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setLevel(1);
    setQuestion(null);
    setTimeLeft(null);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setLoading(false);
    setLifelines({
      fiftyFifty: true,
      audiencePoll: true,
      doubleDip: true,
      flipQuestion: true
    });
    setStatus(GameStatus.LANGUAGE_SELECT);
  };

  if (status === GameStatus.LANGUAGE_SELECT) {
    return <LanguageSelection onSelect={handleLanguageSelect} />;
  }

  if (status === GameStatus.WON || status === GameStatus.LOST) {
    return (
      <GameOver 
        isWon={status === GameStatus.WON} 
        levelReached={level} 
        language={language} 
        onRestart={restartGame} 
      />
    );
  }

  const currentLevelAmount = MONEY_TREE.find(l => l.id === level)?.amount || "₹0";

  return (
    <div className="min-h-screen kbc-bg flex flex-col md:flex-row relative overflow-hidden">
      {status === GameStatus.DISCLAIMER && (
        <Disclaimer language={language} onStart={handleStartGame} />
      )}

      {pollData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-lg p-6">
          <div className="bg-[#001a33] p-12 rounded-[2rem] gold-border max-w-md w-full text-center shadow-[0_0_60px_rgba(212,175,55,0.4)]">
            <h3 className="gold-text text-4xl font-black mb-10 tracking-widest uppercase italic">Audience Poll</h3>
            <div className="flex items-end justify-around h-64 mb-10 gap-3">
              {Object.entries(pollData).map(([key, value]) => (
                <div key={key} className="flex flex-col items-center w-full group">
                  <div className="text-white text-sm font-bold mb-2 opacity-0 group-hover:opacity-100 transition-opacity">{value}%</div>
                  <div 
                    className="bg-gradient-to-t from-blue-800 to-cyan-400 w-full rounded-t-xl transition-all duration-1000 border-x border-t border-white/20 shadow-2xl" 
                    style={{ height: `${value}%` }}
                  ></div>
                  <span className="text-black bg-white w-full mt-2 font-black rounded-b-lg py-2 text-xl">{key}</span>
                </div>
              ))}
            </div>
            <button 
              onClick={() => setPollData(null)}
              className="bg-gradient-to-r from-[#d4af37] to-[#8a6d3b] text-black font-black py-4 px-12 rounded-full hover:scale-105 active:scale-95 transition-all shadow-xl"
            >
              CONTINUE
            </button>
          </div>
        </div>
      )}

      <div className="flex-grow flex flex-col items-center relative">
        <div className="w-full flex justify-between items-center px-6 py-5 z-10 bg-black/40 border-b border-[#d4af37]/30 backdrop-blur-md">
          <div className="flex items-center space-x-4">
            <div className="w-16 h-16 bg-gradient-to-br from-[#d4af37] via-[#8a6d3b] to-[#d4af37] rounded-full flex items-center justify-center text-black font-black text-3xl shadow-[0_0_20px_rgba(212,175,55,0.5)] border-4 border-white/20">
              {level}
            </div>
            <div className="flex flex-col">
              <span className="text-white font-black uppercase text-xs tracking-widest opacity-70">Current Level</span>
              <span className="gold-text font-black text-xl tracking-tighter">{currentLevelAmount}</span>
            </div>
          </div>

          <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />

          <div className="w-20 md:w-32 flex justify-end">
            {timeLeft !== null && status === GameStatus.PLAYING && !loading && (
              <div className={`text-3xl md:text-5xl font-black text-center border-4 rounded-full w-16 h-16 md:w-24 md:h-24 flex items-center justify-center shadow-2xl transition-all duration-500 bg-black/60 ${timeLeft <= 10 ? 'border-red-600 text-red-600 animate-pulse' : 'border-blue-500 text-blue-500'}`}>
                {timeLeft}
              </div>
            )}
            {timeLeft === null && !loading && status === GameStatus.PLAYING && (
              <div className="text-cyan-400 border-2 border-cyan-400/50 rounded-xl px-4 py-2 text-xs font-black uppercase tracking-tighter bg-cyan-950/20">
                Deep Thinking
              </div>
            )}
          </div>
        </div>

        <div className="h-12 flex items-center justify-center w-full">
          {isDoubleDipActive && (
            <div className="bg-gradient-to-r from-orange-600 to-red-600 text-white px-8 py-1 rounded-full text-xs font-black tracking-widest uppercase animate-pulse shadow-xl border border-white/30">
              Double Dip Active
            </div>
          )}
        </div>

        <div className="flex-grow flex flex-col items-center justify-center w-full relative z-0">
          {loading ? (
            <div className="flex flex-col items-center justify-center space-y-10">
              <div className="relative">
                <div className="w-24 h-24 border-8 border-white/5 rounded-full"></div>
                <div className="w-24 h-24 border-8 border-t-[#d4af37] border-transparent rounded-full animate-spin absolute top-0 left-0 shadow-[0_0_30px_#d4af37]"></div>
              </div>
              <p className="text-white gold-text text-2xl animate-pulse font-black uppercase tracking-widest text-center px-10">
                {language === Language.HINDI ? 'अगला पड़ाव आ रहा है...' : 'Fetching Next Level...'}
              </p>
            </div>
          ) : question ? (
            <QuizArea 
              question={question} 
              language={language} 
              hiddenOptions={hiddenOptions}
              isDoubleDipActive={isDoubleDipActive}
              onAnswer={handleAnswer} 
            />
          ) : null}
        </div>

        <div className="absolute bottom-0 w-full h-[40vh] bg-gradient-to-t from-[#001a33] to-transparent pointer-events-none -z-10"></div>
      </div>

      <div className="hidden lg:block w-96 h-screen shadow-[0_0_50px_rgba(0,0,0,0.8)] relative z-50">
        <Sidebar currentLevel={level} />
      </div>
    </div>
  );
};

export default App;

