            {timeLeft !== null && status === GameStatus.PLAYING && !loading && (
              <div className={`text-3xl md:text-5xl font-black text-center border-4 rounded-full w-16 h-16 md:w-24 md:h-24 flex items-center justify-center shadow-2xl transition-all duration-500 bg-black/60 ${timeLeft <= 10 ? 'border-red-600 text-red-600 animate-pulse' : 'border-blue-500 text-blue-500'}`}>
