import { GoogleGenAI, Type } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const CATEGORIES = [
  "Indian History",
  "World History",
  "Geography of India",
  "World Geography",
  "General Science & Biology",
  "Sports (Cricket, Olympics, Football)",
  "Indian Cinema (Bollywood) & Arts",
  "International Affairs & Politics",
  "Indian Constitution & Civics",
  "Literature & Famous Books",
  "Indian Mythology (Only occasional)",
  "Technology & Innovations",
  "Economics & Business",
  "Space Exploration",
  "Environment & Wildlife"
];

export const fetchQuestion = async (level: number, lang: Language): Promise<Question> => {
  const difficulty = level <= 4 ? "very easy" : level <= 8 ? "medium" : level <= 12 ? "hard" : "extremely obscure and difficult";
  const languageName = lang === Language.HINDI ? "Hindi" : "English";

  // Explicitly pick a category to force variety
  const category = CATEGORIES[Math.floor(Math.random() * CATEGORIES.length)];
  const randomFactor = Math.random().toString(36).substring(7);

  const prompt = `Act as a professional KBC (Kaun Banega Crorepati) question setter. 
  Generate a UNIQUE, high-quality multiple-choice question in ${languageName}.

  SPECIFIC CATEGORY: ${category}
  DIFFICULTY LEVEL: ${difficulty} (Level ${level} of 15)
  RANDOM SEED: ${randomFactor}

  Strict Rules:
  1. DO NOT generate simple or common trivia.
  2. For higher levels (10-15), the fact must be very obscure and factual.
  3. Ensure the options are plausible but only one is correct.
  4. Ensure the question is relevant to the ${category} category specifically.
  5. If the language is Hindi, use professional and formal Hindi (Shuddh Hindi) as used in the show.

  Return ONLY a JSON object matching the requested schema.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING, description: "The quiz question text." },
            options: {
              type: Type.OBJECT,
              properties: {
                A: { type: Type.STRING },
                B: { type: Type.STRING },
                C: { type: Type.STRING },
                D: { type: Type.STRING }
              },
              required: ["A", "B", "C", "D"]
            },
            correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
            explanation: { type: Type.STRING, description: "A brief factual explanation about the correct answer." }
          },
          required: ["text", "options", "correctAnswer", "explanation"]
        }
      }
    });

    const text = response.text || "{}";
    const data = JSON.parse(text);
    return data as Question;
  } catch (error) {
    console.error("Error fetching question:", error);
    // Dynamic Fallback based on category
    return {
      text: lang === Language.HINDI 
        ? "इनमें से कौन सा स्मारक शाहजहाँ द्वारा अपनी पत्नी की याद में बनाया गया था?" 
        : "Which of these monuments was built by Shah Jahan in memory of his wife?",
      options: {
        A: lang === Language.HINDI ? "कुतुब मीनार" : "Qutub Minar",
        B: lang === Language.HINDI ? "ताजमहल" : "Taj Mahal",
        C: lang === Language.HINDI ? "लाल किला" : "Red Fort",
        D: lang === Language.HINDI ? "हवा महल" : "Hawa Mahal"
      },
      correctAnswer: "B",
      explanation: "Taj Mahal was built by Mughal emperor Shah Jahan in memory of his third wife, Mumtaz Mahal."
    };
  }
};

