import { GoogleGenAI, Type } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const CATEGORIES = [
  "Indian Freedom Struggle",
  "Ancient Indian Science & Medicine",
  "World Exploration & Voyagers",
  "Nobel Prizes & Global Awards",
  "Indian Railways & Infrastructure",
  "Wildlife & Endangered Species",
  "Nuclear & Space Programs of India",
  "Classical Arts & Dance Forms",
  "Global Economic History",
  "Inventions & Their Inventors",
  "Indian Judicial System & Landmarks",
  "Famous Speeches in History",
  "Olympic Games Records",
  "Traditional Cuisines & Origins",
  "Modern Tech (AI, Quantum, Robotics)",
  "Geopolitics & UN History",
  "Flora of the Indian Subcontinent",
  "Obscure Literary Works",
  "Indian Cinema's Golden Era",
  "Architecture of Medieval India"
];

export const fetchQuestion = async (level: number, lang: Language): Promise<Question> => {
  // Determine model based on difficulty
  // Use Pro for extremely hard questions to ensure factual depth and complexity
  const modelName = level >= 13 ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const difficultyMap = {
    low: "straightforward but professional",
    mid: "moderately challenging, requires good general knowledge",
    high: "difficult, focusing on specific details or numbers",
    expert: "extremely obscure, historical, or scientific facts that are rarely known"
  };

  let difficultyTier = "low";
  if (level > 4) difficultyTier = "mid";
  if (level > 9) difficultyTier = "high";
  if (level > 12) difficultyTier = "expert";

  const languageName = lang === Language.HINDI ? "Hindi" : "English";

  // Explicitly pick a category to force variety
  const category = CATEGORIES[Math.floor(Math.random() * CATEGORIES.length)];
  const randomFactor = Math.random().toString(36).substring(7);

  const prompt = `Act as the Chief Content Creator for Kaun Banega Crorepati.
  Generate one UNIQUE multiple-choice question.

  CATEGORY: ${category}
  DIFFICULTY LEVEL: ${level}/15 (${difficultyMap[difficultyTier as keyof typeof difficultyMap]})
  LANGUAGE: ${languageName}
  RANDOM SEED: ${randomFactor}

  STRICT CONTENT RULES:
  1. DO NOT mention Mythology (Gods/Goddesses) unless the category is specifically about it.
  2. AVOID common trivia (e.g., "Who is the President?", "Capital of Japan"). 
  3. High-level questions (10-15) must involve obscure dates, specific middle names, exact measurements, or rare historical footnotes.
  4. Ensure all four options are from the same context/domain to prevent easy guessing.
  5. For ${languageName} questions, use the formal tone used by Amitabh Bachchan on the show.
  6. Double-check all facts for 100% accuracy.

  Return ONLY a JSON object.`;

  try {
    const config: any = {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          text: { type: Type.STRING },
          options: {
            type: Type.OBJECT,
            properties: {
              A: { type: Type.STRING },
              B: { type: Type.STRING },
              C: { type: Type.STRING },
              D: { type: Type.STRING }
            },
            required: ["A", "B", "C", "D"]
          },
          correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
          explanation: { type: Type.STRING }
        },
        required: ["text", "options", "correctAnswer", "explanation"]
      }
    };

    // Add thinking budget for Pro model to handle complex obscure facts
    if (level >= 13) {
      config.thinkingConfig = { thinkingBudget: 4000 };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: config
    });

    const text = response.text || "{}";
    const data = JSON.parse(text);
    return data as Question;
  } catch (error) {
    console.error("Error fetching question:", error);
    // Dynamic Fallback
    return {
      text: lang === Language.HINDI 
        ? "इनमें से किस नदी का उद्गम स्थल भारत के बाहर है?" 
        : "Which of these rivers originates outside of India?",
      options: {
        A: lang === Language.HINDI ? "गंगा" : "Ganga",
        B: lang === Language.HINDI ? "ब्रह्मपुत्र" : "Brahmaputra",
        C: lang === Language.HINDI ? "यमुना" : "Yamuna",
        D: lang === Language.HINDI ? "गोदावरी" : "Godavari"
      },
      correctAnswer: "B",
      explanation: "The Brahmaputra originates in Tibet (China) near Mount Kailash."
    };
  }
};

