              <span className="gold-text font-black text-xl tracking-tighter">{currentLevelAmount}</span>
            </div>
          </div>

          <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />

          <div className="w-20 md:w-32 flex justify-end">
            {timeLeft !== null && status === GameStatus.PLAYING && !loading && (
              <div className="relative w-16 h-16 md:w-24 md:h-24 flex items-center justify-center group">
                <svg className="absolute inset-0 transform -rotate-90 w-full h-full" viewBox="0 0 100 100">
                  {/* Background Circle */}
                  <circle
                    cx="50" cy="50" r={radius}
                    stroke="currentColor"
                    strokeWidth="6"
                    fill="transparent"
                    className="text-gray-800/50"
                  />
                  {/* Progress Circle */}
                  <circle
                    cx="50" cy="50" r={radius}
                    stroke="currentColor"
                    strokeWidth="6"
                    fill="transparent"
                    strokeDasharray={circumference}
                    strokeDashoffset={progressOffset}
                    strokeLinecap="round"
                    className={`transition-all duration-1000 ease-linear ${
                      timeLeft <= 10 ? 'text-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]' : 'text-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]'
                    }`}
                  />
                </svg>
                <div className={`relative z-10 text-3xl md:text-5xl font-black text-center transition-all duration-500 ${timeLeft <= 10 ? 'text-red-600 animate-pulse' : 'text-blue-500'}`}>
                  {timeLeft}
                </div>
