    if (timerRef.current) clearInterval(timerRef.current);
    setLevel(1);
    setQuestion(null);
    setTimeLeft(null);
    setMaxTime(null);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setLoading(false);
    setLifelines({
      fiftyFifty: true,
      audiencePoll: true,
      doubleDip: true,
      flipQuestion: true
    });
    setStatus(GameStatus.LANGUAGE_SELECT);
  };

  const isHindi = language === Language.HINDI;

  if (status === GameStatus.LANGUAGE_SELECT) {
    return <LanguageSelection onSelect={handleLanguageSelect} />;
  }

  if (status === GameStatus.WON || status === GameStatus.LOST) {
    return (
      <GameOver 
        isWon={status === GameStatus.WON} 
        levelReached={level} 
        language={language} 
        onRestart={restartGame} 
      />
    );
  }

  const currentLevelAmount = MONEY_TREE.find(l => l.id === level)?.amount || "₹0";

  // Circular Progress Calculation
  const radius = 42;
  const circumference = 2 * Math.PI * radius;
  const progressOffset = timeLeft !== null && maxTime !== null 
    ? circumference - (timeLeft / maxTime) * circumference 
    : 0;

  return (
    <div className="min-h-screen kbc-bg flex flex-col md:flex-row relative overflow-hidden">
      {status === GameStatus.DISCLAIMER && (
        <Disclaimer language={language} onStart={handleStartGame} />
      )}

      {pollData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-gradient-to-b from-[#001a33] to-[#000d1a] p-10 md:p-14 rounded-[3rem] gold-border max-w-lg w-full text-center shadow-[0_0_100px_rgba(212,175,55,0.3)] border-2 border-[#d4af37]/50">
            <h3 className="gold-text text-3xl md:text-5xl font-black mb-12 tracking-widest uppercase italic drop-shadow-lg">
              {isHindi ? 'ऑडियन्स पोल' : 'Audience Poll'}
            </h3>
            <div className="flex items-end justify-around h-72 mb-12 gap-4 px-2">
              {(Object.entries(pollData) as [string, number][]).map(([key, value]) => (
                <div key={key} className="flex flex-col items-center w-full group relative">
                  <div className="text-white text-lg font-bold mb-3 transition-all duration-500 opacity-100 scale-110">
                    {value}%
                  </div>
                  <div 
                    className={`relative w-full rounded-t-2xl transition-all duration-[1500ms] ease-out shadow-2xl border-x border-t border-white/20 ${value > 0 ? 'bg-gradient-to-t from-blue-900 via-blue-600 to-cyan-300' : 'bg-gray-800/20'}`} 
                    style={{ height: `${value}%` }}
                  >
                    <div className="absolute inset-0 bg-white/10 opacity-20 rounded-t-2xl animate-pulse"></div>
                  </div>
                  <div className="w-full mt-4 bg-white text-black font-black rounded-xl py-3 text-2xl shadow-lg transform group-hover:scale-105 transition-transform">
                    {key}
                  </div>
                </div>
              ))}
            </div>
            <button 
              onClick={() => setPollData(null)}
              className="group relative bg-gradient-to-r from-[#d4af37] via-[#f1d27a] to-[#8a6d3b] text-black font-black py-5 px-16 rounded-full hover:scale-110 active:scale-95 transition-all shadow-[0_10px_40px_rgba(212,175,55,0.4)] overflow-hidden"
            >
              <span className="relative z-10 text-xl tracking-tighter">
                {isHindi ? 'जारी रखें' : 'CONTINUE'}
              </span>
              <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-500 skew-x-12"></div>
            </button>
          </div>
        </div>
      )}

      <div className="flex-grow flex flex-col items-center relative">
        <div className="w-full flex justify-between items-center px-6 py-5 z-10 bg-black/40 border-b border-[#d4af37]/30 backdrop-blur-md">
          <div className="flex items-center space-x-4">
            <div className="w-16 h-16 bg-gradient-to-br from-[#d4af37] via-[#8a6d3b] to-[#d4af37] rounded-full flex items-center justify-center text-black font-black text-3xl shadow-[0_0_20px_rgba(212,175,55,0.5)] border-4 border-white/20">
              {level}
            </div>
            <div className="flex flex-col">
              <span className="text-white font-black uppercase text-xs tracking-widest opacity-70">
                {isHindi ? 'वर्तमान स्तर' : 'Current Level'}
              </span>
              <span className="gold-text font-black text-xl tracking-tighter">{currentLevelAmount}</span>
            </div>
          </div>

          <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />

          <div className="w-20 md:w-32 flex justify-end">
            {timeLeft !== null && status === GameStatus.PLAYING && !loading && (
              <div className={`relative w-16 h-16 md:w-24 md:h-24 flex items-center justify-center group ${
                timeLeft <= 10 ? 'animate-timer-critical' : timeLeft > 25 ? 'animate-timer-pulse' : ''
              }`}>
                <svg className="absolute inset-0 transform -rotate-90 w-full h-full" viewBox="0 0 100 100">
                  {/* Background Circle */}
                  <circle
                    cx="50" cy="50" r={radius}
                    stroke="currentColor"
                    strokeWidth="8"
                    fill="transparent"
                    className="text-gray-800/50"
                  />
                  {/* Progress Circle */}
                  <circle
                    cx="50" cy="50" r={radius}
                    stroke="currentColor"
                    strokeWidth="8"
                    fill="transparent"
                    strokeDasharray={circumference}
                    strokeDashoffset={progressOffset}
                    strokeLinecap="round"
                    className={`transition-all duration-1000 ease-linear ${
                      timeLeft <= 10 ? 'text-red-500' : 'text-blue-500'
                    }`}
                  />
                </svg>
                <div className={`relative z-10 text-3xl md:text-5xl font-black text-center transition-all duration-500 ${
                  timeLeft <= 10 ? 'text-white' : 'text-blue-400'
                }`}>
                  {timeLeft}
                </div>
              </div>
            )}
            {timeLeft === null && !loading && status === GameStatus.PLAYING && (
              <div className="text-cyan-400 border-2 border-cyan-400/50 rounded-xl px-4 py-2 text-xs font-black uppercase tracking-tighter bg-cyan-950/20 animate-pulse">
                No Timer
              </div>
            )}
          </div>
        </div>

        <div className="h-12 flex items-center justify-center w-full">
          {isDoubleDipActive && (
            <div className="bg-gradient-to-r from-orange-600 to-red-600 text-white px-8 py-1 rounded-full text-xs font-black tracking-widest uppercase animate-pulse shadow-xl border border-white/30">
              Double Dip Active
            </div>
          )}
        </div>

        <div className="flex-grow flex flex-col items-center justify-center w-full relative z-0">
          {loading ? (
            <div className="flex flex-col items-center justify-center space-y-10">
              <div className="relative">
                <div className="w-24 h-24 border-8 border-white/5 rounded-full"></div>
                <div className="w-24 h-24 border-8 border-t-[#d4af37] border-transparent rounded-full animate-spin absolute top-0 left-0 shadow-[0_0_30px_#d4af37]"></div>
              </div>
              <p className="text-white gold-text text-2xl animate-pulse font-black uppercase tracking-widest text-center px-10">
                {language === Language.HINDI ? 'अगला पड़ाव आ रहा है...' : 'Fetching Next Level...'}
              </p>
            </div>
          ) : question ? (
            <QuizArea 
              question={question} 
              language={language} 
              hiddenOptions={hiddenOptions}
              isDoubleDipActive={isDoubleDipActive}
              onAnswer={handleAnswer} 
            />
          ) : null}
        </div>

        <div className="absolute bottom-0 w-full h-[40vh] bg-gradient-to-t from-[#001a33] to-transparent pointer-events-none -z-10"></div>
      </div>

      <div className="hidden md:block w-72 lg:w-96 h-screen shadow-[0_0_50px_rgba(0,0,0,0.8)] relative z-50">
        <Sidebar currentLevel={level} />
      </div>
    </div>
  );
};

