            <div className="w-10 h-10 md:w-16 md:h-16 bg-gradient-to-br from-[#d4af37] via-[#8a6d3b] to-[#d4af37] rounded-full flex items-center justify-center text-black font-black text-xl md:text-3xl shadow-[0_0_20px_rgba(212,175,55,0.5)] border-2 md:border-4 border-white/20">
