                      timeLeft <= 10 ? 'text-red-500' : 'text-blue-500'
                    }`}
                  />
                </svg>
                <div className={`relative z-10 text-xl md:text-5xl font-black text-center transition-all duration-500 ${
                  timeLeft <= 10 ? 'text-white' : 'text-blue-400'
                }`}>
                  {timeLeft}
                </div>
              </div>
            )}
            {timeLeft === null && !loading && status === GameStatus.PLAYING && (
              <div className="text-cyan-400 border border-cyan-400/50 rounded-lg px-2 py-1 text-[8px] md:text-xs font-black uppercase tracking-tighter bg-cyan-950/20 animate-pulse">
                {isHindi ? 'कोई समय सीमा नहीं' : 'No Timer'}
              </div>
            )}
