        <div className="h-8 md:h-12 flex items-center justify-center w-full">
          {isDoubleDipActive && (
            <div className="bg-gradient-to-r from-orange-600 to-red-600 text-white px-6 md:px-8 py-1 rounded-full text-[8px] md:text-xs font-black tracking-widest uppercase animate-pulse shadow-xl border border-white/30">
              Double Dip Active
            </div>
          )}
        </div>

        <div className="flex-grow flex flex-col items-center justify-center w-full relative z-0 pb-24 md:pb-0">
          {loading ? (
            <div className="flex flex-col items-center justify-center space-y-6 md:space-y-10">
              <div className="relative">
                <div className="w-16 h-16 md:w-24 md:h-24 border-4 md:border-8 border-white/5 rounded-full"></div>
                <div className="w-16 h-16 md:w-24 md:h-24 border-4 md:border-8 border-t-[#d4af37] border-transparent rounded-full animate-spin absolute top-0 left-0 shadow-[0_0_30px_#d4af37]"></div>
              </div>
              <p className="text-white gold-text text-lg md:text-2xl animate-pulse font-black uppercase tracking-widest text-center px-10">
                {language === Language.HINDI ? 'अगला पड़ाव आ रहा है...' : 'Fetching Next Level...'}
              </p>
            </div>
          ) : question ? (
            <QuizArea 
              question={question} 
              language={language} 
              hiddenOptions={hiddenOptions}
              isDoubleDipActive={isDoubleDipActive}
              onAnswer={handleAnswer} 
            />
          ) : null}
        </div>

        {/* Mobile Bottom Lifelines Bar */}
        <div className="fixed bottom-0 left-0 right-0 z-[100] md:hidden bg-gradient-to-t from-[#000d1a] to-black/80 backdrop-blur-xl border-t border-[#d4af37]/30 pb-safe">
           <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />
        </div>

        <div className="absolute bottom-0 w-full h-[30vh] md:h-[40vh] bg-gradient-to-t from-[#001a33] to-transparent pointer-events-none -z-10"></div>
      </div>

      <div className="hidden md:block w-72 lg:w-96 h-screen shadow-[0_0_50px_rgba(0,0,0,0.8)] relative z-50">
        <Sidebar currentLevel={level} />
      </div>
    </div>
  );
};

