          <span className="text-[8px] md:text-xs text-white mt-1 font-bold uppercase tracking-tighter text-center line-clamp-1 px-1">
            {item.label === 'audiencePoll' ? 'Poll' : item.label === 'fiftyFifty' ? '50:50' : item.label}
          </span>
