import React, { useState, useEffect } from 'react';
import { Question, Language } from '../types';

interface Props {
  question: Question;
  language: Language;
  hiddenOptions: string[];
  isDoubleDipActive: boolean;
  onAnswer: (correct: boolean, isFirstAttemptOfDoubleDip: boolean) => void;
}

const QuizArea: React.FC<Props> = ({ question, language, hiddenOptions, isDoubleDipActive, onAnswer }) => {
  const [selected, setSelected] = useState<string | null>(null);
  const [locked, setLocked] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [failedOptions, setFailedOptions] = useState<string[]>([]);

  useEffect(() => {
    setSelected(null);
    setLocked(false);
    setShowResult(false);
    setFailedOptions([]);
  }, [question]);

  const handleOptionClick = (key: string) => {
    if (!locked && !hiddenOptions.includes(key) && !failedOptions.includes(key)) {
      setSelected(key);
    }
  };

  const lockAnswer = () => {
    if (!selected) return;
    setLocked(true);

    // Simulating Amitabh Bachchan's suspense before revealing the answer
    setTimeout(() => {
      const isCorrect = selected === question.correctAnswer;

      if (isCorrect) {
        setShowResult(true);
        setTimeout(() => onAnswer(true, false), 2000);
      } else {
        if (isDoubleDipActive && failedOptions.length === 0) {
          // Double Dip first chance logic
          setFailedOptions(prev => [...prev, selected]);
          setSelected(null);
          setLocked(false);
          onAnswer(false, true);
        } else {
          setShowResult(true);
          setTimeout(() => onAnswer(false, false), 3000);
        }
      }
    }, 2000);
  };

  const getOptionClass = (key: string) => {
    // 1. Check if hidden by 50-50
    if (hiddenOptions.includes(key)) return 'opacity-0 pointer-events-none cursor-default';

    // 2. Check if failed during Double Dip
    if (failedOptions.includes(key)) return 'bg-red-900/40 border-red-500 opacity-50 cursor-not-allowed';

    // 3. Result Reveal State
    if (showResult) {
      if (key === question.correctAnswer) {
        return 'option-correct scale-[1.02] md:scale-105 z-10 shadow-[0_0_30px_#22c55e]';
      }
      if (key === selected && selected !== question.correctAnswer) {
        return 'option-wrong shadow-[0_0_30px_#ef4444]';
      }
      // If it's not the correct one and not the selected wrong one, make it dimmed
      return 'opacity-40 grayscale-[0.5]';
    }

    // 4. Selection/Locking State
    if (selected === key) {
      return locked 
        ? 'bg-orange-600 border-white animate-pulse shadow-[0_0_20px_rgba(234,88,12,0.8)]' 
        : 'option-selected scale-[1.02] md:scale-105';
    }

    return 'hover:bg-blue-900/40';
  };

  const isHindi = language === Language.HINDI;

  return (
    <div className="flex flex-col items-center justify-center p-2 md:p-8 space-y-4 md:space-y-8 w-full max-w-5xl mx-auto">
      {/* Question Box */}
      <div className="w-full p-6 md:p-12 bg-black/80 border-2 border-[#d4af37] rounded-2xl md:rounded-3xl text-center shadow-[0_0_30px_rgba(212,175,55,0.2)] relative">
        <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-[#001a33] px-4 py-0.5 border border-[#d4af37] rounded-full text-[10px] gold-text font-bold uppercase tracking-widest whitespace-nowrap">
          {isHindi ? 'प्रश्न' : 'Question'}
        </div>
        <h2 className="text-lg md:text-3xl font-bold text-white leading-tight md:leading-relaxed drop-shadow-md">
          {question.text}
        </h2>
      </div>

      {/* Options Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3 md:gap-6 w-full px-2">
        {Object.entries(question.options).map(([key, value]) => (
          <button
            key={key}
            onClick={() => handleOptionClick(key)}
            disabled={locked || hiddenOptions.includes(key) || failedOptions.includes(key)}
            className={`option-button flex items-center px-6 md:px-10 py-3 md:py-5 text-white text-sm md:text-xl font-semibold min-h-[60px] md:min-h-[90px] transition-all duration-300 ${getOptionClass(key)}`}
          >
            <span className="gold-text mr-3 md:mr-5 font-black text-lg md:text-2xl">{key}:</span>
            <span className="text-left leading-tight line-clamp-3">{value}</span>
          </button>
        ))}
      </div>

      {/* Action Area */}
      <div className="h-16 md:h-24 flex items-center justify-center w-full">
        {selected && !locked && !showResult && (
          <button
            onClick={lockAnswer}
            className="bg-gradient-to-r from-orange-600 to-orange-400 text-white font-black py-3 md:py-4 px-12 md:px-20 rounded-full text-lg md:text-2xl shadow-[0_10px_30px_rgba(234,88,12,0.4)] transition-all transform hover:scale-110 active:scale-95 animate-bounce uppercase tracking-tighter"
          >
            {isHindi ? 'लॉक किया जाए!' : 'Lock Kiya Jaye!'}
          </button>
        )}
        {locked && !showResult && (
          <div className="text-orange-400 font-black text-lg md:text-2xl animate-pulse uppercase italic tracking-widest">
            {isHindi ? 'चेक कर रहे हैं...' : 'Checking...'}
          </div>
        )}
        {showResult && (
          <div className={`font-black text-2xl md:text-4xl animate-scale-in uppercase tracking-tighter ${selected === question.correctAnswer ? 'text-green-400' : 'text-red-500'}`}>
            {selected === question.correctAnswer 
              ? (isHindi ? 'बिल्कुल सही जवाब!' : 'Correct Answer!') 
              : (isHindi ? 'गलत जवाब!' : 'Wrong Answer!')}
          </div>
        )}
      </div>

      {/* Explanation Box */}
      {showResult && (
        <div className="w-full p-4 md:p-6 bg-blue-900/20 border-l-4 border-yellow-500 rounded-lg text-white animate-fade-in backdrop-blur-md">
          <p className="gold-text font-bold uppercase text-[10px] mb-1">{isHindi ? 'विवरण' : 'EXPLANATION'}</p>
          <p className="text-sm md:text-lg leading-snug italic">"{question.explanation}"</p>
        </div>
      )}
    </div>
  );
};

export default QuizArea;

import React, { useState, useEffect, useRef } from 'react';
import LanguageSelection from './components/LanguageSelection';
import Disclaimer from './components/Disclaimer';
import Sidebar from './components/Sidebar';
import QuizArea from './components/QuizArea';
import Lifelines from './components/Lifelines';
import GameOver from './components/GameOver';
import { Language, GameStatus, Question, Lifelines as LifelinesType, PollData } from './types';
import { fetchQuestion } from './services/gemini';
import { getTimerForLevel, MONEY_TREE } from './constants';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.LANGUAGE_SELECT);
  const [language, setLanguage] = useState<Language>(Language.ENGLISH);
  const [level, setLevel] = useState(1);
  const [question, setQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(false);
  const [timeLeft, setTimeLeft] = useState<number | null>(null);
  const [maxTime, setMaxTime] = useState<number | null>(null);
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);
  const [pollData, setPollData] = useState<PollData | null>(null);
  const [isDoubleDipActive, setIsDoubleDipActive] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [lifelines, setLifelines] = useState<LifelinesType>({
    fiftyFifty: true,
    audiencePoll: true,
    doubleDip: true,
    flipQuestion: true
  });

  const timerRef = useRef<any>(null);

  const loadQuestion = async (currLevel: number, lang: Language) => {
    setLoading(true);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setIsSidebarOpen(false);

    try {
      const q = await fetchQuestion(currLevel, lang);
      const initialTime = getTimerForLevel(currLevel);

      setMaxTime(initialTime);
      setTimeLeft(initialTime);
      setQuestion(q);
    } catch (error) {
      console.error("Failed to load question", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (status === GameStatus.PLAYING && timeLeft !== null && timeLeft > 0 && !loading) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev === null) return null;
          if (prev <= 1) {
            clearInterval(timerRef.current);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else if (status === GameStatus.PLAYING && timeLeft === 0 && !loading) {
      handleAnswer(false, false);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status, timeLeft, loading]);

  const handleLanguageSelect = (lang: Language) => {
    setLanguage(lang);
    setStatus(GameStatus.DISCLAIMER);
  };

  const handleStartGame = () => {
    setStatus(GameStatus.PLAYING);
    loadQuestion(1, language);
  };

  const handleAnswer = (isCorrect: boolean, isFirstAttemptOfDoubleDip: boolean) => {
    if (isFirstAttemptOfDoubleDip) return;
    if (timerRef.current) clearInterval(timerRef.current);

    if (isCorrect) {
      setTimeout(() => {
        if (level === 15) {
          setStatus(GameStatus.WON);
        } else {
          const nextLevel = level + 1;
          setLevel(nextLevel);
          loadQuestion(nextLevel, language);
        }
      }, 2000);
    } else {
      setTimeout(() => {
        setStatus(GameStatus.LOST);
      }, 1500);
    }
  };

  const useLifeline = (type: keyof LifelinesType) => {
    if (!question || loading) return;

    // Deactivate used lifeline
    setLifelines(prev => ({ ...prev, [type]: false }));

    if (type === 'fiftyFifty') {
      const incorrect = Object.keys(question.options).filter(k => k !== question.correctAnswer);
      const shuffled = incorrect.sort(() => 0.5 - Math.random());
      setHiddenOptions(shuffled.slice(0, 2));
    } else if (type === 'audiencePoll') {
      const correct = question.correctAnswer as keyof PollData;
      const data: PollData = { A: 0, B: 0, C: 0, D: 0 };
      const visibleKeys = (['A', 'B', 'C', 'D'] as (keyof PollData)[]).filter(k => !hiddenOptions.includes(k));
      const correctVal = Math.floor(Math.random() * 20) + 65; 
      data[correct] = correctVal;
      let remaining = 100 - correctVal;
      const otherVisibleKeys = visibleKeys.filter(k => k !== correct);
      if (otherVisibleKeys.length > 0) {
        otherVisibleKeys.forEach((key, index) => {
          if (index === otherVisibleKeys.length - 1) {
            data[key] = remaining;
          } else {
            const val = Math.floor(Math.random() * remaining);
            data[key] = val;
            remaining -= val;
          }
        });
      }
      setPollData(data);
    } else if (type === 'doubleDip') {
      setIsDoubleDipActive(true);
    } else if (type === 'flipQuestion') {
      loadQuestion(level, language);
    }
  };

  const restartGame = () => {
    // 1. Clear intervals
    if (timerRef.current) clearInterval(timerRef.current);

    // 2. Reset Core State
    setLevel(1);
    setQuestion(null);
    setTimeLeft(null);
    setMaxTime(null);
    setLoading(false);
    setStatus(GameStatus.LANGUAGE_SELECT);

    // 3. Reset UI & Help State
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setIsSidebarOpen(false);

    // 4. Reset Lifelines (Crucial Fix)
    setLifelines({
      fiftyFifty: true,
      audiencePoll: true,
      doubleDip: true,
      flipQuestion: true
    });
  };

  const isHindi = language === Language.HINDI;

  if (status === GameStatus.LANGUAGE_SELECT) {
    return <LanguageSelection onSelect={handleLanguageSelect} />;
  }

  if (status === GameStatus.WON || status === GameStatus.LOST) {
    return <GameOver isWon={status === GameStatus.WON} levelReached={level} language={language} onRestart={restartGame} />;
  }

  const currentLevelAmount = MONEY_TREE.find(l => l.id === level)?.amount || "₹0";
  const radius = 42;
  const circumference = 2 * Math.PI * radius;
  const progressOffset = timeLeft !== null && maxTime !== null 
    ? circumference - (timeLeft / maxTime) * circumference 
    : 0;

  return (
    <div className="min-h-screen kbc-bg flex flex-col md:flex-row relative overflow-hidden text-white">
      {status === GameStatus.DISCLAIMER && (
        <Disclaimer language={language} onStart={handleStartGame} />
      )}

      {/* Mobile Drawer Navigation (Money Tree) */}
      <div className={`fixed inset-0 z-[120] md:hidden transition-opacity duration-300 ${isSidebarOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
        <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
        <div className={`absolute left-0 top-0 bottom-0 w-[80%] max-w-sm bg-[#000d1a] shadow-2xl transition-transform duration-300 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className="flex items-center justify-between p-4 border-b border-[#d4af37]/30 bg-black/40">
             <h3 className="gold-text font-black uppercase tracking-widest">{isHindi ? 'धन वृक्ष' : 'Money Tree'}</h3>
             <button onClick={() => setIsSidebarOpen(false)} className="text-[#d4af37] text-2xl p-2"><i className="fas fa-times"></i></button>
           </div>
           <div className="h-[calc(100%-64px)] overflow-y-auto">
             <Sidebar currentLevel={level} />
           </div>
        </div>
      </div>

      {/* Main Container */}
      <div className="flex-grow flex flex-col relative min-h-screen z-10">
        {/* Responsive Header */}
        <header className="w-full flex justify-between items-center px-4 md:px-6 py-3 md:py-5 bg-black/60 border-b border-[#d4af37]/30 backdrop-blur-md sticky top-0 z-[50]">
          <div className="flex items-center space-x-3">
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="md:hidden w-10 h-10 flex items-center justify-center text-[#d4af37] border border-[#d4af37]/40 rounded-lg bg-blue-900/20 active:scale-90 transition-transform"
            >
              <i className="fas fa-bars"></i>
            </button>
            <div className="flex flex-col">
              <span className="text-gray-400 font-bold uppercase text-[8px] md:text-xs tracking-widest">{isHindi ? 'वर्तमान स्तर' : 'LEVEL'} {level}</span>
              <span className="gold-text font-black text-sm md:text-xl leading-none">{currentLevelAmount}</span>
            </div>
          </div>

          <div className="hidden md:block">
            <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />
          </div>

          <div className="flex items-center">
             {timeLeft !== null && status === GameStatus.PLAYING && !loading ? (
              <div className={`relative w-12 h-12 md:w-20 md:h-20 flex items-center justify-center rounded-full ${timeLeft <= 10 ? 'animate-timer-critical' : 'animate-timer-pulse'}`}>
                <svg className="absolute inset-0 transform -rotate-90 w-full h-full" viewBox="0 0 100 100">
                  <circle cx="50" cy="50" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-800/30" />
                  <circle cx="50" cy="50" r={radius} stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={circumference} strokeDashoffset={progressOffset} strokeLinecap="round" className={`transition-all duration-1000 ${timeLeft <= 10 ? 'text-red-500' : 'text-blue-400'}`} />
                </svg>
                <span className={`relative z-10 text-xl md:text-3xl font-black ${timeLeft <= 10 ? 'text-white' : 'text-blue-200'}`}>{timeLeft}</span>
              </div>
            ) : (
              <div className="bg-blue-900/30 border border-blue-400/30 rounded-full px-4 py-1.5 text-[10px] md:text-xs font-black text-blue-300 uppercase animate-pulse">
                {isHindi ? 'समय सीमा नहीं' : 'Free Thinking'}
              </div>
            )}
          </div>
        </header>

        {/* Dynamic Status Banner */}
        <div className="h-8 md:h-12 flex items-center justify-center w-full">
          {isDoubleDipActive && (
            <div className="bg-gradient-to-r from-orange-600 to-red-600 text-white px-6 py-1 rounded-full text-[10px] font-black tracking-widest uppercase animate-bounce shadow-lg border border-white/20">
              Double Dip ACTIVE
            </div>
          )}
        </div>

        {/* Content Area */}
        <main className="flex-grow flex flex-col items-center justify-center px-2 md:px-4 pb-24 md:pb-0 overflow-y-auto">
          {loading ? (
            <div className="animate-scale-in flex flex-col items-center space-y-8">
              <div className="relative w-20 h-20">
                <div className="absolute inset-0 border-4 border-[#d4af37]/20 rounded-full"></div>
                <div className="absolute inset-0 border-4 border-t-[#d4af37] rounded-full animate-spin"></div>
              </div>
              <p className="gold-text text-xl md:text-2xl font-black uppercase tracking-widest text-center animate-pulse">
                {isHindi ? 'अगला प्रश्न आ रहा है...' : 'PREPARING QUESTION...'}
              </p>
            </div>
          ) : question ? (
            <div className="w-full max-w-5xl animate-fade-in">
              <QuizArea 
                question={question} 
                language={language} 
                hiddenOptions={hiddenOptions}
                isDoubleDipActive={isDoubleDipActive}
                onAnswer={handleAnswer} 
              />
            </div>
          ) : null}
        </main>

        {/* Mobile Fixed Lifelines */}
        <footer className="fixed bottom-0 left-0 right-0 z-[100] md:hidden bg-black/80 backdrop-blur-xl border-t border-[#d4af37]/20 safe-bottom-padding">
           <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />
        </footer>
      </div>

      {/* Desktop Sidebar */}
      <aside className="hidden md:block w-72 lg:w-80 h-screen shadow-2xl relative z-40 border-l border-[#d4af37]/20">
        <Sidebar currentLevel={level} />
      </aside>

      {/* Global Overlays */}
      {pollData && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-xl p-4 animate-fade-in">
          <div className="bg-[#000d1a] p-6 md:p-12 rounded-3xl gold-border max-w-lg w-full text-center animate-scale-in">
            <h3 className="gold-text text-2xl md:text-4xl font-black mb-8 uppercase italic">{isHindi ? 'ऑडियन्स पोल' : 'Audience Poll'}</h3>
            <div className="flex items-end justify-around h-48 md:h-64 mb-8 gap-2">
              {(Object.entries(pollData) as [string, number][]).map(([key, value]) => (
                <div key={key} className="flex flex-col items-center w-full">
                  <span className="text-white text-xs font-bold mb-1">{value}%</span>
                  <div className="relative w-full bg-blue-900/30 rounded-t-lg overflow-hidden border-x border-t border-white/10" style={{ height: `${value}%` }}>
                    <div className="absolute inset-0 bg-gradient-to-t from-blue-700 to-cyan-400 animate-pulse"></div>
                  </div>
                  <div className="w-full mt-2 bg-white text-black font-black py-1 rounded-md text-sm">{key}</div>
                </div>
              ))}
            </div>
            <button onClick={() => setPollData(null)} className="bg-gradient-to-r from-[#d4af37] to-[#8a6d3b] text-black font-black py-3 px-12 rounded-full hover:scale-105 transition-transform active:scale-95 shadow-xl">
              {isHindi ? 'आगे बढ़ें' : 'CONTINUE'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
