  "Obscure Literary Works",
  "Indian Cinema's Golden Era",
  "Architecture of Medieval India"
];

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const fetchQuestion = async (level: number, lang: Language, attempt = 0): Promise<Question> => {
  // Use pro model for higher levels to ensure quality and reasoning
  const modelName = level >= 11 ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const difficultyMap = {
    low: "straightforward but professional",
    mid: "moderately challenging",
    high: "difficult, focusing on specific details",
    expert: "extremely obscure historical or scientific facts"
  };

  let difficultyTier = "low";
  if (level > 4) difficultyTier = "mid";
  if (level > 9) difficultyTier = "high";
  if (level > 12) difficultyTier = "expert";

  const languageName = lang === Language.HINDI ? "Hindi" : "English";
  const category = CATEGORIES[Math.floor(Math.random() * CATEGORIES.length)];
  const randomFactor = Math.random().toString(36).substring(7);

  const prompt = `Act as an expert KBC quiz master. Create one unique, factually accurate multiple-choice question.
  CATEGORY: ${category}
  DIFFICULTY LEVEL: ${level} out of 15 (Tone: ${difficultyMap[difficultyTier as keyof typeof difficultyMap]})
  LANGUAGE: ${languageName}
  UNIQUE ID: ${randomFactor}

  CRITICAL REQUIREMENTS:
  1. Return ONLY a pure JSON object.
  2. The question must be 100% factually correct.
  3. Incorrect options must be plausible to mislead the player.
  4. Explanation should be concise but informative.
  5. For high levels (10+), avoid common trivia; look for deep, specific knowledge.`;

  try {
    const config: any = {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          text: { type: Type.STRING },
          options: {
            type: Type.OBJECT,
            properties: {
              A: { type: Type.STRING },
              B: { type: Type.STRING },
              C: { type: Type.STRING },
              D: { type: Type.STRING }
            },
            required: ["A", "B", "C", "D"]
          },
          correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
          explanation: { type: Type.STRING }
        },
        required: ["text", "options", "correctAnswer", "explanation"]
      }
    };

    // Give Pro model more room to think for high-stakes questions
    if (level >= 11) {
      config.thinkingConfig = { thinkingBudget: 8000 };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: config
    });

    const text = response.text || "{}";
    const data = JSON.parse(text);

    // Validate data structure before returning
    if (!data.text || !data.options || !data.correctAnswer) {
      throw new Error("Invalid question structure returned from API");
    }

    return data as Question;
  } catch (error: any) {
    console.warn(`[API] Attempt ${attempt + 1} failed for Level ${level}:`, error?.message || error);

    // Exponential backoff for retries
    if (attempt < 3) {
      const waitTime = Math.pow(2, attempt) * 1500;
      await sleep(waitTime);
      return fetchQuestion(level, lang, attempt + 1);
    }

    // FINAL FALLBACK: If all attempts fail, provide a high-quality static question to prevent app crash
    console.error(`[API] Max retries reached. Using fallback question.`);

    const fallbackQuestions: Record<Language, Question> = {
      [Language.HINDI]: {
        text: "इनमें से कौन सा शहर गंगा नदी के तट पर स्थित नहीं है?",
        options: {
          A: "वाराणसी",
          B: "कानपुर",
          C: "लखनऊ",
          D: "पटना"
        },
        correctAnswer: "C",
        explanation: "लखनऊ गोमती नदी के किनारे बसा है, जबकि वाराणसी, कानपुर और पटना गंगा नदी के किनारे हैं।"
      },
      [Language.ENGLISH]: {
        text: "Which of these cities is NOT situated on the banks of the river Ganges?",
        options: {
          A: "Varanasi",
          B: "Kanpur",
          C: "Lucknow",
          D: "Patna"
        },
        correctAnswer: "C",
        explanation: "Lucknow is located on the banks of the river Gomti. The others are on the Ganges."
      }
    };

    return fallbackQuestions[lang];
  }
};

import React, { useState, useEffect } from 'react';
import { Question, Language } from '../types';

interface Props {
  question: Question;
  language: Language;
  hiddenOptions: string[];
  isDoubleDipActive: boolean;
  onAnswer: (correct: boolean, isFirstAttemptOfDoubleDip: boolean) => void;
}

const QuizArea: React.FC<Props> = ({ question, language, hiddenOptions, isDoubleDipActive, onAnswer }) => {
  const [selected, setSelected] = useState<string | null>(null);
  const [locked, setLocked] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [failedOptions, setFailedOptions] = useState<string[]>([]);

  useEffect(() => {
    setSelected(null);
    setLocked(false);
    setShowResult(false);
    setFailedOptions([]);
  }, [question]);

  const handleOptionClick = (key: string) => {
    // Only allow selection if not locked and not revealed
    if (!locked && !showResult && !hiddenOptions.includes(key) && !failedOptions.includes(key)) {
      setSelected(key);
    }
  };

  const lockAnswer = () => {
    if (!selected) return;
    setLocked(true);

    // SUSPENSE PHASE (2 seconds of Orange/Pulse)
    setTimeout(() => {
      const isCorrect = selected === question.correctAnswer;
      setShowResult(true);

      if (isCorrect) {
        // Correct Answer reveal
        setTimeout(() => onAnswer(true, false), 2500);
      } else {
        // Incorrect Answer reveal
        if (isDoubleDipActive && failedOptions.length === 0) {
          // Double Dip first chance logic
          setTimeout(() => {
            setFailedOptions(prev => [...prev, selected]);
            setSelected(null);
            setLocked(false);
            setShowResult(false);
            onAnswer(false, true);
          }, 1500);
        } else {
          // Final wrong answer
          setTimeout(() => onAnswer(false, false), 3500);
        }
      }
    }, 2000);
  };

  const getOptionClass = (key: string) => {
    // 1. Lifeline concealment
    if (hiddenOptions.includes(key)) return 'opacity-0 pointer-events-none cursor-default';
    if (failedOptions.includes(key)) return 'opacity-40 grayscale cursor-not-allowed bg-red-950/20';

    // 2. Result state (The Reveal)
    if (showResult) {
      // Always show the correct answer as green
      if (key === question.correctAnswer) {
        return 'option-correct scale-[1.05] z-10 shadow-[0_0_30px_#22c55e]';
      }
      // If the selected one was wrong, show it as red
      if (key === selected && selected !== question.correctAnswer) {
        return 'option-wrong shadow-[0_0_30px_#ef4444] scale-[0.98]';
      }
      // Everything else dims
      return 'opacity-20 grayscale-[0.9] blur-[1px]';
    }

    // 3. Selection and Locking state (The Orange Phase)
    if (selected === key) {
      return locked 
        ? 'bg-gradient-to-r from-orange-600 to-yellow-500 border-white animate-pulse shadow-[0_0_25px_rgba(234,88,12,0.9)] scale-[1.03] z-10' 
        : 'bg-orange-500 border-white shadow-[0_0_15px_rgba(234,88,12,0.5)] scale-[1.02]';
    }

    // 4. Default state
    return 'hover:bg-blue-900/40 border-[#d4af37]/40';
  };

  const isHindi = language === Language.HINDI;

  return (
    <div className="flex flex-col items-center justify-center p-2 md:p-8 space-y-4 md:space-y-8 w-full max-w-5xl mx-auto">
      {/* Question Box */}
      <div className="w-full p-6 md:p-12 bg-black/80 border-2 border-[#d4af37] rounded-2xl md:rounded-3xl text-center shadow-[0_0_40px_rgba(212,175,55,0.15)] relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#d4af37] to-transparent"></div>
        <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-[#001a33] px-6 py-0.5 border border-[#d4af37] rounded-full text-[10px] gold-text font-black uppercase tracking-[0.3em] whitespace-nowrap z-20">
          {isHindi ? 'प्रश्न' : 'Question'}
        </div>
        <h2 className="text-xl md:text-3xl lg:text-4xl font-bold text-white leading-tight md:leading-relaxed drop-shadow-lg relative z-10">
          {question.text}
        </h2>
      </div>

      {/* Options Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-8 w-full px-2 max-w-4xl">
        {Object.entries(question.options).map(([key, value]) => (
          <button
            key={key}
            onClick={() => handleOptionClick(key)}
            disabled={locked || showResult || hiddenOptions.includes(key) || failedOptions.includes(key)}
            className={`option-button group flex items-center px-8 md:px-12 py-4 md:py-6 text-white text-base md:text-xl font-bold min-h-[70px] md:min-h-[100px] transition-all duration-300 ${getOptionClass(key)}`}
          >
            <span className={`mr-4 md:mr-6 font-black text-xl md:text-2xl transition-colors duration-300 ${selected === key || (showResult && (key === selected || key === question.correctAnswer)) ? 'text-white' : 'gold-text'}`}>
              {key}:
            </span>
            <span className="text-left leading-tight line-clamp-2 md:line-clamp-3 flex-grow">{value}</span>
          </button>
        ))}
      </div>

      {/* Action Area */}
      <div className="h-20 md:h-32 flex items-center justify-center w-full">
        {selected && !locked && !showResult && (
          <button
            onClick={lockAnswer}
            className="group relative bg-gradient-to-r from-orange-600 via-orange-500 to-orange-400 text-white font-black py-4 md:py-5 px-14 md:px-24 rounded-full text-xl md:text-3xl shadow-[0_15px_40px_rgba(234,88,12,0.4)] transition-all transform hover:scale-110 active:scale-95 animate-bounce uppercase tracking-tighter overflow-hidden"
          >
            <span className="relative z-10">{isHindi ? 'लॉक किया जाए!' : 'Lock Kiya Jaye!'}</span>
            <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 skew-x-12"></div>
          </button>
        )}
        {locked && !showResult && (
          <div className="flex flex-col items-center">
            <div className="text-orange-400 font-black text-2xl md:text-4xl animate-pulse uppercase italic tracking-[0.2em] drop-shadow-[0_0_10px_rgba(251,146,60,0.5)]">
              {isHindi ? 'चेक कर रहे हैं...' : 'Checking...'}
            </div>
            <div className="flex space-x-2 mt-4">
              {[1, 2, 3].map(i => (
                <div key={i} className={`w-3 h-3 rounded-full bg-orange-500 animate-bounce`} style={{ animationDelay: `${i * 0.2}s` }}></div>
              ))}
            </div>
          </div>
        )}
        {showResult && (
          <div className={`font-black text-3xl md:text-5xl animate-scale-in uppercase tracking-tighter drop-shadow-2xl text-center ${selected === question.correctAnswer ? 'text-green-400' : 'text-red-500'}`}>
            {selected === question.correctAnswer 
              ? (isHindi ? 'बिल्कुल सही जवाब!' : 'Correct Answer!') 
              : (isHindi ? 'गलत जवाब!' : 'Wrong Answer!')}
          </div>
        )}
      </div>

      {/* Explanation Box */}
      {showResult && (
        <div className="w-full max-w-3xl p-5 md:p-8 bg-black/60 border-l-4 border-[#d4af37] rounded-xl text-white animate-fade-in backdrop-blur-xl shadow-2xl">
          <div className="flex items-center mb-3">
            <i className="fas fa-info-circle gold-text mr-3 text-xl"></i>
            <span className="gold-text font-black uppercase text-xs md:text-sm tracking-widest">{isHindi ? 'विवरण' : 'EXPLANATION'}</span>
          </div>
          <p className="text-base md:text-xl leading-relaxed italic text-blue-50 font-medium">"{question.explanation}"</p>
        </div>
      )}
    </div>
  );
};

